301	
302		output reg        mem_axi_rvalid,
303		input             mem_axi_rready,
304		output reg [31:0] mem_axi_rdata,
305	
306		output reg        tests_passed
307	);
308		reg [31:0]   memory [0:128*1024/4-1] /* verilator public */;
309		reg verbose;
310		initial verbose = $test$plusargs("verbose") || VERBOSE;
311	
312		reg axi_test;
313		initial axi_test = $test$plusargs("axi_test") || AXI_TEST;
314	
