317			mem_axi_wready = 0;
318			mem_axi_bvalid = 0;
319			mem_axi_arready = 0;
320			mem_axi_rvalid = 0;
321			tests_passed = 0;
322		end
323	
324		reg [63:0] xorshift64_state = 64'd88172645463325252;
325	
326		task xorshift64_next;
327			begin
328				// see page 4 of Marsaglia, George (July 2003). "Xorshift RNGs". Journal of Statistical Software 8 (14).
329				xorshift64_state = xorshift64_state ^ (xorshift64_state << 13);
330				xorshift64_state = xorshift64_state ^ (xorshift64_state >>  7);
331				xorshift64_state = xorshift64_state ^ (xorshift64_state << 17);
332			end
333		endtask
334	
335		reg [2:0] fast_axi_transaction = ~0;
336		reg [4:0] async_axi_transaction = ~0;
337		reg [4:0] delay_axi_transaction = 0;
338	
339		always @(posedge clk) begin
340			if (axi_test) begin
341					xorshift64_next;
342					{fast_axi_transaction, async_axi_transaction, delay_axi_transaction} <= xorshift64_state;
343			end
344		end
345	
346		reg latched_raddr_en = 0;
347		reg latched_waddr_en = 0;
348		reg latched_wdata_en = 0;
349	
350		reg fast_raddr = 0;
351		reg fast_waddr = 0;
352		reg fast_wdata = 0;
353	
354		reg [31:0] latched_raddr;
355		reg [31:0] latched_waddr;
356		reg [31:0] latched_wdata;
357		reg [ 3:0] latched_wstrb;
358		reg        latched_rinsn;
359	
360		task handle_axi_arvalid; begin
361			mem_axi_arready <= 1;
362			latched_raddr = mem_axi_araddr;
363			latched_rinsn = mem_axi_arprot[2];
364			latched_raddr_en = 1;
365			fast_raddr <= 1;
366		end endtask
367	
368		task handle_axi_awvalid; begin
369			mem_axi_awready <= 1;
370			latched_waddr = mem_axi_awaddr;
371			latched_waddr_en = 1;
372			fast_waddr <= 1;
373		end endtask
374	
375		task handle_axi_wvalid; begin
376			mem_axi_wready <= 1;
377			latched_wdata = mem_axi_wdata;
378			latched_wstrb = mem_axi_wstrb;
379			latched_wdata_en = 1;
380			fast_wdata <= 1;
381		end endtask
382	
383		task handle_axi_rvalid; begin
384			if (verbose)
385				$display("RD: ADDR=%08x DATA=%08x%s", latched_raddr, memory[latched_raddr >> 2], latched_rinsn ? " INSN" : "");
386			if (latched_raddr < 128*1024) begin
387				mem_axi_rdata <= memory[latched_raddr >> 2];
388				mem_axi_rvalid <= 1;
389				latched_raddr_en = 0;
390			end else begin
391				$display("OUT-OF-BOUNDS MEMORY READ FROM %08x", latched_raddr);
392				$finish;
393			end
394		end endtask
395	
396		task handle_axi_bvalid; begin
397			if (verbose)
398				$display("WR: ADDR=%08x DATA=%08x STRB=%04b", latched_waddr, latched_wdata, latched_wstrb);
399			if (latched_waddr < 128*1024) begin
400				if (latched_wstrb[0]) memory[latched_waddr >> 2][ 7: 0] <= latched_wdata[ 7: 0];
401				if (latched_wstrb[1]) memory[latched_waddr >> 2][15: 8] <= latched_wdata[15: 8];
402				if (latched_wstrb[2]) memory[latched_waddr >> 2][23:16] <= latched_wdata[23:16];
403				if (latched_wstrb[3]) memory[latched_waddr >> 2][31:24] <= latched_wdata[31:24];
404			end else
405			if (latched_waddr == 32'h1000_0000) begin
406				if (verbose) begin
407					if (32 <= latched_wdata && latched_wdata < 128)
408						$display("OUT: '%c'", latched_wdata[7:0]);
409					else
410						$display("OUT: %3d", latched_wdata);
411				end else begin
412					$write("%c", latched_wdata[7:0]);
413	`ifndef VERILATOR
414					$fflush();
415	`endif
416				end
417			end else
418			if (latched_waddr == 32'h2000_0000) begin
419				if (latched_wdata == 123456789)
420					tests_passed = 1;
421			end else begin
422				$display("OUT-OF-BOUNDS MEMORY WRITE TO %08x", latched_waddr);
423				$finish;
424			end
425			mem_axi_bvalid <= 1;
426			latched_waddr_en = 0;
427			latched_wdata_en = 0;
428		end endtask
429	
430		always @(negedge clk) begin
431			if (mem_axi_arvalid && !(latched_raddr_en || fast_raddr) && async_axi_transaction[0]) handle_axi_arvalid;
432			if (mem_axi_awvalid && !(latched_waddr_en || fast_waddr) && async_axi_transaction[1]) handle_axi_awvalid;
433			if (mem_axi_wvalid  && !(latched_wdata_en || fast_wdata) && async_axi_transaction[2]) handle_axi_wvalid;
434			if (!mem_axi_rvalid && latched_raddr_en && async_axi_transaction[3]) handle_axi_rvalid;
435			if (!mem_axi_bvalid && latched_waddr_en && latched_wdata_en && async_axi_transaction[4]) handle_axi_bvalid;
436		end
437	
438		always @(posedge clk) begin
439			mem_axi_arready <= 0;
440			mem_axi_awready <= 0;
441			mem_axi_wready <= 0;
442	
443			fast_raddr <= 0;
444			fast_waddr <= 0;
445			fast_wdata <= 0;
446	
447			if (mem_axi_rvalid && mem_axi_rready) begin
448				mem_axi_rvalid <= 0;
449			end
450	
451			if (mem_axi_bvalid && mem_axi_bready) begin
452				mem_axi_bvalid <= 0;
453			end
454	
455			if (mem_axi_arvalid && mem_axi_arready && !fast_raddr) begin
456				latched_raddr = mem_axi_araddr;
457				latched_rinsn = mem_axi_arprot[2];
458				latched_raddr_en = 1;
459			end
